module RefModule(
    input [3:0] in,
    output [3:0] out
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB ;
    supply0 VNB ;

    // Invert MSB
    wire __out_tmp = in[2:0];
    assign out[2:0] = __out_tmp; 
    assign out[3] = ~in[3];  // Directly invert MSB instead of using unknown module

endmodule
